1	/**
2	 * Login Page
3	 *
4	 * User authentication page with login form and profile validation.
5	 */
6	
7	'use client';
8	
9	import LoginForm from '@/components/shared/auth/LoginForm';
10	import LiquidGradient from '@/components/shared/ui/LiquidGradient';
11	import PasswordUpdateModal from '@/components/shared/ui/PasswordUpdateModal';
12	import { LoginPageSkeleton } from '@/components/shared/ui/skeletons/LoginSkeletons';
13	import Image from 'next/image';
14	import { Suspense } from 'react';
15	
16	// Hooks
17	import { useLoginPageData } from '@/lib/hooks/auth/useLoginPageData';
18	
19	// Assets
20	import EOSLogo from '/public/EOS_Logo.png';
21	import SlotMachineImage from '/public/slotMachine.png';
22	
23	/**
24	 * Login Page Content Component
25	 */
26	function LoginPageContent() {
27	  // ============================================================================
28	  // Hooks & State
29	  // ============================================================================
30	  const hook = useLoginPageData();
31	
32	  const {
33	    identifier,
34	    password,
35	    showPassword,
36	    rememberMe,
37	    errors,
38	    message,
39	    messageType,
40	    loading,
41	    redirecting,
42	    authLoading,
43	    showPasswordUpdateModal,
44	    isCashierTempChange,
45	    isForced,
46	    setIdentifier,
47	    setPassword,
48	    setShowPassword,
49	    setRememberMe,
50	    handleLogin,
51	    setShowPasswordUpdateModal,
52	    handlePasswordUpdate,
53	    handleLogout,
54	  } = hook;
55	
56	  // Show loading skeleton while checking authentication status
57	  if (authLoading) return <LoginPageSkeleton />;
58	
59	  return (
60	    <>
61	      {/* Background Component */}
62	      <LiquidGradient />
63	
64	      {/* Main Container */}
65	      <div className="flex min-h-screen items-center justify-center bg-transparent p-4">
66	        <div className="w-full max-w-4xl overflow-hidden rounded-2xl bg-white shadow-2xl">
67	          <div className="flex flex-col md:flex-row">
68	            <div className="w-full p-12 md:w-1/2">
69	              <div className="mx-auto w-full max-w-sm">
70	                <div className="text-center">
71	                  <Image
72	                    src={EOSLogo}
73	                    alt="Logo"
74	                    width={150}
75	                    height={75}
76	                    className="mb-6 inline-block"
77	                    priority
78	                  />
79	                </div>
80	                <LoginForm
81	                  identifier={identifier}
82	                  setIdentifier={setIdentifier}
83	                  password={password}
84	                  setPassword={setPassword}
85	                  showPassword={showPassword}
86	                  setShowPassword={setShowPassword}
87	                  rememberMe={rememberMe}
88	                  setRememberMe={setRememberMe}
89	                  errors={errors}
90	                  message={message}
91	                  messageType={messageType}
92	                  loading={loading}
93	                  redirecting={redirecting}
94	                  handleLogin={handleLogin}
95	                />
96	              </div>
97	            </div>
98	            <div className="relative min-h-[250px] w-full md:min-h-0 md:w-1/2">
99	              <Image
100	                src={SlotMachineImage}
101	                alt="Casino"
102	                fill
103	                priority
104	                className="object-cover"
105	              />
106	              <div className="absolute bottom-10 left-10 pr-4">
107	                <h2 className="text-2xl font-bold text-white">
108	                  Casino Management System
109	                </h2>
110	              </div>
111	            </div>
112	          </div>
113	        </div>
114	      </div>
115	
116	      <PasswordUpdateModal
117	        open={showPasswordUpdateModal}
118	        onClose={() => setShowPasswordUpdateModal(false)}
119	        onUpdate={handlePasswordUpdate}
120	        loading={loading}
121	        isForced={isForced}
122	        isCashierTempChange={isCashierTempChange}
123	        onLogout={handleLogout}
124	        initialPhone={hook.initialPhone}
125	      />
126	    </>
127	  );
128	}
129	
130	export default function LoginPage() {
131	  return (
132	    <Suspense fallback={<LoginPageSkeleton />}>
133	      <LoginPageContent />
134	    </Suspense>
135	  );
136	}
