1	/**
2	 * Application Selection Component
3	 *
4	 * Displays role/application selection screen for high-level users (Developer, Admin, Manager, Location Admin).
5	 * Allows users to choose between CMS and VAULT applications.
6	 *
7	 * Features:
8	 * - Two large selection cards: "Casino Management System" and "Vault Management"
9	 * - Role-based display (only shown to authorized roles)
10	 * - Redirects to selected application
11	 * - Bypasses selection if APPLICATION env var is set
12	 *
13	 * @module components/shared/auth/ApplicationSelection
14	 */
15	'use client';
16	
17	import { useRouter } from 'next/navigation';
18	import { useEffect, useState } from 'react';
19	import { useUserStore } from '@/lib/store/userStore';
20	import { Button } from '@/components/shared/ui/button';
21	import { Card, CardContent } from '@/components/shared/ui/card';
22	import { CreditCard, MonitorSpeaker } from 'lucide-react';
23	import Image from 'next/image';
24	
25	/**
26	 * Check if user has high-level role that requires application selection
27	 */
28	function hasHighLevelRole(userRoles: string[] | undefined): boolean {
29	  if (!userRoles || userRoles.length === 0) return false;
30	  const highLevelRoles = ['developer', 'admin', 'manager', 'location admin'];
31	  return userRoles.some(role => highLevelRoles.includes(role));
32	}
33	
34	type ApplicationSelectionProps = {
35	  onSelect: (application: 'CMS' | 'VAULT') => void;
36	};
37	
38	export default function ApplicationSelection({
39	  onSelect,
40	}: ApplicationSelectionProps) {
41	  // ============================================================================
42	  // State & Hooks
43	  // ============================================================================
44	  const router = useRouter();
45	  const { user } = useUserStore();
46	  const [isSelecting, setIsSelecting] = useState(false);
47	
48	  // ============================================================================
49	  // Effects
50	  // ============================================================================
51	  // Check if user should see this screen
52	  useEffect(() => {
53	    if (!user) {
54	      router.push('/login');
55	      return;
56	    }
57	
58	    // If APPLICATION env var is set, bypass selection
59	    // Note: This is a server-side env var, so we check it on mount
60	    // In production, this would be set at build/deploy time
61	    // For development, you can set it in .env.local
62	    const appEnv =
63	      process.env.NEXT_PUBLIC_APPLICATION || process.env.APPLICATION;
64	    if (appEnv) {
65	      const appMode = appEnv as 'CMS' | 'VAULT';
66	      onSelect(appMode);
67	      return;
68	    }
69	
70	    // Only show selection to high-level roles
71	    if (!hasHighLevelRole(user.roles)) {
72	      // Non-high-level users go directly to CMS
73	      onSelect('CMS');
74	    }
75	  }, [user, router, onSelect]);
76	
77	  // ============================================================================
78	  // Handlers
79	  // ============================================================================
80	  const handleSelect = (application: 'CMS' | 'VAULT') => {
81	    if (isSelecting) return;
82	    setIsSelecting(true);
83	    onSelect(application);
84	  };
85	
86	  // ============================================================================
87	  // Render
88	  // ============================================================================
89	  // Don't render if user doesn't have high-level role or APPLICATION is set
90	  if (
91	    !user ||
92	    !hasHighLevelRole(user.roles) ||
93	    process.env.NEXT_PUBLIC_APPLICATION
94	  ) {
95	    return null;
96	  }
97	
98	  return (
99	    <div className="flex min-h-screen items-center justify-center bg-gradient-to-br from-blue-50 to-indigo-100 p-4">
100	      <div className="w-full max-w-4xl rounded-lg bg-white p-8 shadow-xl">
101	        {/* Header */}
102	        <div className="mb-8 text-center">
103	          <div className="mb-4 flex justify-center">
104	            <Image
105	              src="/EOS_Logo.png"
106	              alt="Evolution One CMS Logo"
107	              width={64}
108	              height={64}
109	              className="h-16 w-16"
110	            />
111	          </div>
112	          <h1 className="mb-2 text-2xl font-bold text-gray-900">
113	            Welcome back, {user.profile?.firstName || user.username || 'User'}
114	          </h1>
115	          <p className="text-gray-600">Please select your workspace:</p>
116	        </div>
117	
118	        {/* Application Selection Cards */}
119	        <div className="grid gap-6 md:grid-cols-2">
120	          {/* CMS Card */}
121	          <Card
122	            className="cursor-pointer transition-all hover:scale-105 hover:shadow-lg"
123	            onClick={() => handleSelect('CMS')}
124	          >
125	            <CardContent className="flex flex-col items-center p-8 text-center">
126	              <div className="mb-4 flex h-20 w-20 items-center justify-center rounded-full bg-blue-100">
127	                <MonitorSpeaker className="h-10 w-10 text-blue-600" />
128	              </div>
129	              <h2 className="mb-2 text-xl font-semibold text-gray-900">
130	                Casino Management System
131	              </h2>
132	              <p className="mb-6 text-sm text-gray-600">
133	                Manage machines, locations, collections, and reports
134	              </p>
135	              <Button
136	                className="w-full"
137	                onClick={e => {
138	                  e.stopPropagation();
139	                  handleSelect('CMS');
140	                }}
141	                disabled={isSelecting}
142	              >
143	                Access Dashboard
144	              </Button>
145	            </CardContent>
146	          </Card>
147	
148	          {/* VAULT Card */}
149	          <Card
150	            className="cursor-pointer transition-all hover:scale-105 hover:shadow-lg"
151	            onClick={() => handleSelect('VAULT')}
152	          >
153	            <CardContent className="flex flex-col items-center p-8 text-center">
154	              <div className="mb-4 flex h-20 w-20 items-center justify-center rounded-full bg-orange-100">
155	                <CreditCard className="h-10 w-10 text-orange-600" />
156	              </div>
157	              <h2 className="mb-2 text-xl font-semibold text-gray-900">
158	                Vault Management
159	              </h2>
160	              <p className="mb-6 text-sm text-gray-600">
161	                Manage vault balance, cash desks, floats, and expenses
162	              </p>
163	              <Button
164	                className="w-full bg-orange-600 hover:bg-orange-700"
165	                onClick={e => {
166	                  e.stopPropagation();
167	                  handleSelect('VAULT');
168	                }}
169	                disabled={isSelecting}
170	              >
171	                Access Vault
172	              </Button>
173	            </CardContent>
174	          </Card>
175	        </div>
176	      </div>
177	    </div>
178	  );
179	}
