1	/**
2	 * Protected Route Component
3	 * Wrapper component that protects pages requiring authentication and authorization.
4	 *
5	 * Features:
6	 * - Authenticates user before allowing access
7	 * - Checks admin access requirements
8	 * - Validates page-specific permissions
9	 * - Redirects to login if unauthenticated
10	 * - Shows NoRoleAssigned message for users without roles
11	 * - Supports both local and database permission checks
12	 *
13	 * @param children - Child components to render if authorized
14	 * @param requireAdminAccess - Whether admin/developer role is required
15	 * @param requiredPage - Specific page permission required
16	 */
17	'use client';
18	
19	import PageLayout from '@/components/shared/layout/PageLayout';
20	import { NoRoleAssigned } from '@/components/shared/ui/NoRoleAssigned';
21	import { useAuth } from '@/lib/hooks/useAuth';
22	import { shouldShowNoRoleMessage } from '@/lib/utils/licencee';
23	import {
24	  PageName,
25	  hasAdminAccessDb,
26	  hasPageAccess,
27	  hasPageAccessDb,
28	} from '@/lib/utils/permissions';
29	import {
30	  isCashierOnly,
31	  isVaultManagerOnly,
32	} from '@/lib/utils/permissions/client';
33	import { usePathname, useRouter } from 'next/navigation';
34	import { ReactNode, useEffect, useState } from 'react';
35	
36	import { UserRole } from '@/lib/constants';
37	import { UserAuthPayload } from '../../../shared/types';
38	
39	type ProtectedRouteProps = {
40	  children: ReactNode;
41	  requireAdminAccess?: boolean;
42	  requiredPage?: PageName;
43	};
44	
45	export default function ProtectedRoute({
46	  children,
47	  requireAdminAccess = false,
48	  requiredPage,
49	}: ProtectedRouteProps) {
50	  // ============================================================================
51	  // State & Hooks
52	  // ============================================================================
53	  const { user, isLoading, isAuthenticated } = useAuth();
54	  const router = useRouter();
55	  const pathname = usePathname();
56	  const [isChecking, setIsChecking] = useState(true);
57	  const [hasWaitedForRoles, setHasWaitedForRoles] = useState(false);
58	
59	  // ============================================================================
60	  // Effects
61	  // ============================================================================
62	  useEffect(() => {
63	    // Wait for auth to fully load
64	    if (isLoading) return;
65	
66	    const checkAuthentication = async () => {
67	      // First check if user is authenticated
68	      if (!isAuthenticated || !user) {
69	        router.push('/login');
70	        return;
71	      }
72	
73	      // Check if user has roles loaded
74	      if (!user.roles || user.roles.length === 0) {
75	        if (!hasWaitedForRoles) {
76	          // If user has no roles, wait a bit more for them to load
77	          setHasWaitedForRoles(true);
78	          setTimeout(() => {
79	            if (!user.roles || user.roles.length === 0) {
80	              // User has no roles - allow them to see the NoRoleAssigned message
81	              setIsChecking(false);
82	            }
83	          }, 2000);
84	        }
85	        return;
86	      }
87	
88	      // Check if user is cashier-only (has ONLY cashier role, no other roles)
89	      const roles = user.roles as UserRole[];
90	      if (isCashierOnly(roles)) {
91	        // Allow access only to cashier routes
92	        const isCashierRoute =
93	          pathname === '/vault/cashier' ||
94	          pathname?.startsWith('/vault/cashier/');
95	        if (!isCashierRoute) {
96	          router.push('/vault/cashier/payouts');
97	          return;
98	        }
99	      }
100	
101	      // Check if user is vault-manager-only (has ONLY vault-manager role, no other roles)
102	      if (isVaultManagerOnly(roles)) {
103	        // Allow access only to vault management routes
104	        const isVaultRoute =
105	          pathname === '/vault/management' ||
106	          pathname?.startsWith('/vault/management/');
107	        // Block CMS routes (dashboard, locations, cabinets, etc.)
108	        const isCmsRoute =
109	          pathname === '/' ||
110	          pathname?.startsWith('/locations') ||
111	          pathname?.startsWith('/cabinets') ||
112	          pathname?.startsWith('/collection-report') ||
113	          pathname?.startsWith('/sessions') ||
114	          pathname?.startsWith('/members') ||
115	          pathname?.startsWith('/reports') ||
116	          pathname?.startsWith('/administration');
117	        if (isCmsRoute || !isVaultRoute) {
118	          router.push('/vault/management');
119	          return;
120	        }
121	      }
122	
123	      // Check if user is collector-only (has ONLY collector role, no other roles)
124	      const isCollectorOnly =
125	        user.roles.length === 1 && user.roles.includes('collector');
126	
127	      // If collector-only, block access to all pages except collection-report
128	      if (isCollectorOnly) {
129	        // Allow access to collection-report pages (including report details)
130	        const isCollectionReportPage =
131	          pathname === '/collection-report' ||
132	          pathname?.startsWith('/collection-report/');
133	        if (!isCollectionReportPage) {
134	          router.push('/collection-report');
135	          return;
136	        }
137	      }
138	
139	      // Check local permissions first (faster)
140	      const userRoles = (user?.roles || []) as string[];
141	      // STEP 1: Authorization Bypass for Developers and Admins
142	      // Developers have unrestricted access to all pages.
143	      // Admins and Owners have unrestricted access to all pages EXCEPT sessions.
144	      const isDeveloper = userRoles.includes('developer');
145	      const isAdminOrOwner =
146	        userRoles.includes('owner') || userRoles.includes('admin');
147	
148	      const isBypassAuthorized =
149	        isDeveloper || (isAdminOrOwner && requiredPage !== 'sessions');
150	
151	      if (isBypassAuthorized) {
152	        setIsChecking(false);
153	        return;
154	      }
155	
156	      // STEP 2: Standard Authorization Check
157	      if (requireAdminAccess) {
158	        const hasAdminLocal =
159	          user.roles.includes('admin') ||
160	          user.roles.includes('owner') ||
161	          user.roles.includes('developer');
162	        if (!hasAdminLocal) {
163	          router.push('/'); // Redirect to dashboard if not admin
164	          return;
165	        }
166	      }
167	
168	      if (requiredPage) {
169	        const hasPageLocal = hasPageAccess(
170	          user.roles as UserRole[],
171	          requiredPage
172	        );
173	        if (!hasPageLocal) {
174	          router.push('/unauthorized'); // Redirect to unauthorized page
175	          return;
176	        }
177	      }
178	
179	      // Only check database permissions if local check passed and we need to verify
180	      try {
181	        // Check admin access if required (only if local check didn't pass)
182	        if (
183	          requireAdminAccess &&
184	          (!user.roles ||
185	            (!user.roles.includes('admin') &&
186	              !user.roles.includes('owner') &&
187	              !user.roles.includes('developer')))
188	        ) {
189	          const hasAdmin = await hasAdminAccessDb();
190	          if (!hasAdmin) {
191	            router.push('/'); // Redirect to dashboard if not admin
192	            return;
193	          }
194	        }
195	
196	        // Check page access if required (only if local check didn't pass)
197	        if (
198	          requiredPage &&
199	          (!user.roles ||
200	            !hasPageAccess(user.roles as UserRole[], requiredPage))
201	        ) {
202	          const hasPage = await hasPageAccessDb(requiredPage);
203	          if (!hasPage) {
204	            router.push('/unauthorized'); // Redirect to unauthorized page
205	            return;
206	          }
207	        }
208	
209	        setIsChecking(false);
210	        return;
211	      } catch (error) {
212	        console.error('Error checking permissions:', error);
213	        // Only redirect on error if user definitely doesn't have local access
214	        if (
215	          requireAdminAccess &&
216	          user.roles &&
217	          !user.roles.includes('admin') &&
218	          !user.roles.includes('owner') &&
219	          !user.roles.includes('developer')
220	        ) {
221	          router.push('/');
222	        } else if (
223	          requiredPage &&
224	          user.roles &&
225	          !hasPageAccess(user.roles as UserRole[], requiredPage as PageName)
226	        ) {
227	          router.push('/unauthorized');
228	        } else {
229	          setIsChecking(false);
230	        }
231	        return;
232	      }
233	    };
234	
235	    checkAuthentication();
236	  }, [
237	    user,
238	    router,
239	    pathname,
240	    isLoading,
241	    isAuthenticated,
242	    requireAdminAccess,
243	    requiredPage,
244	    hasWaitedForRoles,
245	  ]);
246	
247	  // ============================================================================
248	  // Render
249	  // ============================================================================
250	  // Show loading while checking authentication
251	  if (isLoading || isChecking) return <></>;
252	
253	  // Show NoRoleAssigned message if user has no roles
254	  if (shouldShowNoRoleMessage(user as UserAuthPayload)) {
255	    return (
256	      <PageLayout
257	        headerProps={{
258	          selectedLicencee: '',
259	          setSelectedLicencee: () => {},
260	          disabled: false,
261	        }}
262	        hideOptions={true}
263	        hideLicenceeFilter={true}
264	        mainClassName="flex flex-col flex-1 px-2 py-4 sm:p-6 w-full max-w-full"
265	        showToaster={false}
266	      >
267	        <NoRoleAssigned />
268	      </PageLayout>
269	    );
270	  }
271	
272	  return <>{children}</>;
273	}
