1	/**
2	 * Login API Route
3	 *
4	 * This route handles user authentication and login functionality.
5	 * It supports:
6	 * - Email or username-based login
7	 * - Password validation
8	 * - Remember me functionality
9	 * - JWT token generation
10	 * - Session management
11	 * - Profile validation requirements
12	 * - Password update requirements
13	 * - Secure cookie management
14	 *
15	 * @module app/api/auth/login/route
16	 */
17	
18	import { authenticateUser } from '@/app/api/lib/helpers/auth/auth';
19	import { connectDB } from '@/app/api/lib/middleware/db';
20	import {
21	  createBadRequestResponse,
22	  createErrorResponse,
23	  createServerErrorResponse,
24	  createSuccessResponse,
25	} from '@/app/api/lib/utils/apiResponse';
26	import { getFriendlyErrorMessage } from '@/lib/utils/auth';
27	import { getAuthCookieOptions } from '@/lib/utils/cookieSecurity';
28	import { getClientIP } from '@/lib/utils/ipAddress';
29	import { NextRequest } from 'next/server';
30	import {
31	  logRouteCreate,
32	  logRouteError,
33	  extractUserFromRequest,
34	} from '@/app/api/lib/utils/routeLogger';
35	
36	export const runtime = 'nodejs';
37	
38	/**
39	 * POST /api/auth/login
40	 *
41	 * Authenticates a user and issues JWT access and refresh token cookies. Called
42	 * on every login form submission; extends token lifetime when rememberMe is set.
43	 *
44	 * Body fields:
45	 * @param identifier {string} Required. Email address or username used to look up the account.
46	 * @param password   {string} Required. Plain-text password verified against the stored hash.
47	 * @param rememberMe {boolean} Optional. When true, extends cookie maxAge from 7 days to 30 days.
48	 */
49	export async function POST(request: NextRequest) {
50	  const startTime = Date.now();
51	  const functionName = 'POST /api/auth/login';
52	  const user = extractUserFromRequest(request);
53	
54	  try {
55	    // ============================================================================
56	    // STEP 1: Connect to database
57	    // ============================================================================
58	    await connectDB();
59	
60	    // ============================================================================
61	    // STEP 2: Parse and validate request body
62	    // ============================================================================
63	    const { identifier, password, rememberMe } = await request.json();
64	
65	    // ============================================================================
66	    // STEP 3: Validate identifier format (email or username)
67	    // ============================================================================
68	    if (!identifier || !password) {
69	      return createBadRequestResponse(
70	        'Email/username and password are required.'
71	      );
72	    }
73	
74	    const looksLikeEmail = /\S+@\S+\.\S+/.test(identifier);
75	    const isUsername =
76	      typeof identifier === 'string' && identifier.trim().length >= 3;
77	
78	    if (!(looksLikeEmail || isUsername)) {
79	      return createBadRequestResponse('Invalid identifier format.');
80	    }
81	
82	    // ============================================================================
83	    // STEP 4: Extract client IP and user agent
84	    // ============================================================================
85	    const ipAddress = getClientIP(request) || 'unknown';
86	    const userAgent = request.headers.get('user-agent') || 'unknown';
87	
88	    // ============================================================================
89	    // STEP 5: Authenticate user with credentials
90	    // ============================================================================
91	    const result = await authenticateUser(
92	      identifier,
93	      password,
94	      ipAddress,
95	      userAgent,
96	      rememberMe
97	    );
98	
99	    if (!result.success) {
100	      logRouteError(
101	        functionName,
102	        'POST',
103	        '/api/auth/login',
104	        result.message || 'Authentication failed',
105	        user
106	      );
107	      return createErrorResponse(
108	        result.message || 'Authentication failed',
109	        401
110	      );
111	    }
112	
113	    if (!result.token) {
114	      logRouteError(
115	        functionName,
116	        'POST',
117	        '/api/auth/login',
118	        'No token generated by authenticateUser',
119	        user
120	      );
121	      return createServerErrorResponse(
122	        'Authentication failed - no token generated'
123	      );
124	    }
125	
126	    // ============================================================================
127	    // STEP 6: Generate JWT tokens and create response
128	    // ============================================================================
129	    const response = createSuccessResponse(
130	      {
131	        user: result.user,
132	        expiresAt: result.expiresAt,
133	        requiresPasswordUpdate: result.requiresPasswordUpdate ?? false,
134	        requiresProfileUpdate: result.requiresProfileUpdate ?? false,
135	        invalidProfileFields: result.invalidProfileFields,
136	        invalidProfileReasons: result.invalidProfileReasons,
137	      },
138	      'Login successful'
139	    );
140	
141	    // ============================================================================
142	    // STEP 7: Set secure authentication cookies
143	    // ============================================================================
144	    const clearOptions = getAuthCookieOptions(request, {
145	      expires: new Date(0),
146	    });
147	    response.cookies.set('token', '', clearOptions);
148	    response.cookies.set('refreshToken', '', clearOptions);
149	
150	    const tokenMaxAge = rememberMe ? 30 * 24 * 60 * 60 : 7 * 24 * 60 * 60;
151	    const cookieOptions = getAuthCookieOptions(request, {
