23	/**
24	 * POST /api/auth/refresh
25	 *
26	 * Issues a new short-lived access token using a valid refresh token. Called when
27	 * the access token has expired and a full re-login should be avoided.
28	 *
29	 * Body fields:
30	 * @param refreshToken {string} Optional. The refresh token string. When omitted or set to
31	 *                              the literal "auto", the token is read from the `refreshToken`
32	 *                              HTTP-only cookie instead.
33	 */
34	export async function POST(request: NextRequest) {
35	  const startTime = Date.now();
36	  const functionName = 'POST /api/auth/refresh';
37	  const user = extractUserFromRequest(request);
38	
39	  try {
40	    // ============================================================================
41	    // STEP 1: Parse refresh token from request body or cookies
42	    // ============================================================================
43	    const body = await request.json();
44	    const { refreshToken } = body;
45	
46	    let tokenToUse = refreshToken;
47	    if (!tokenToUse || tokenToUse === 'auto') {
48	      const cookies = request.cookies.get('refreshToken');
49	      tokenToUse = cookies?.value;
50	    }
51	
52	    // ============================================================================
53	    // STEP 2: Validate refresh token presence
54	    // ============================================================================
55	    if (!tokenToUse) {
56	      logRouteError(
