80	        user
81	      );
82	      return NextResponse.json(result, { status: 401 });
83	    }
84	
85	    // ============================================================================
86	    // STEP 4: Set new access token as HTTP-only cookie
87	    // ============================================================================
88	    const response = NextResponse.json({
89	      success: true,
90	      message: 'Token refreshed successfully',
91	    });
92	
93	    response.cookies.set(
94	      'token',
95	      result.token!,
96	      getAuthCookieOptions(request, { maxAge: 60 * 60 })
97	    );
98	
99	    // ============================================================================
100	    // STEP 5: Return success response
101	    // ============================================================================
102	    const duration = Date.now() - startTime;
103	    logRouteFetch(functionName, 'POST', '/api/auth/refresh', 1, user, duration);
104	
105	    return response;
106	  } catch (error) {
107	    const errorMessage = getFriendlyErrorMessage(
108	      error instanceof Error ? error.message : 'Token refresh failed'
