50	      foundUser = await UserModel.findOne({
51	        totpRecoveryToken: recoveryToken,
52	        totpRecoveryExpires: { $gt: new Date() },
53	      });
54	    }
55	
56	    if (!foundUser) {
57	      logRouteError(
58	        functionName,
59	        'POST',
60	        '/api/auth/totp/confirm',
61	        session ? 'User not found' : 'Unauthorized or invalid recovery link',
62	        user
63	      );
64	      return NextResponse.json(
65	        {
66	          error: session
67	            ? 'User not found'
68	            : 'Unauthorized or invalid recovery link',
69	        },
70	        { status: session ? 404 : 401 }
71	      );
72	    }
73	
74	    // ============================================================================
75	    // STEP 1: Determine which secret to verify against
76	    // 1. Recovery setup uses totpTempSecret
77	    // 2. Initial setup uses totpSecret (where totpEnabled is false)
78	    // ============================================================================
79	    const secretToVerify = foundUser.totpTempSecret || foundUser.totpSecret;
80	
81	    if (!secretToVerify) {
82	      logRouteError(
83	        functionName,
84	        'POST',
85	        '/api/auth/totp/confirm',
86	        'Setup not initiated',
87	        user
88	      );
89	      return NextResponse.json(
90	        { error: 'Setup not initiated' },
91	        { status: 400 }
92	      );
93	    }
94	
95	    const isValid = verifyTOTPCode(token, secretToVerify);
96	    if (isValid) {
97	      // ============================================================================
98	      // STEP 2: Promote temp secret to active secret if applicable
99	      // ============================================================================
