105	      foundUser.totpEnabled = true;
106	
107	      // ============================================================================
108	      // STEP 3: Clear recovery tokens
109	      // ============================================================================
110	      foundUser.totpRecoveryToken = null;
111	      foundUser.totpRecoveryExpires = null;
112	
113	      await foundUser.save();
114	
115	      const duration = Date.now() - startTime;
116	      logRouteUpdate(
117	        functionName,
118	        'POST',
119	        '/api/auth/totp/confirm',
120	        1,
121	        user,
122	        duration
123	      );
124	
125	      return NextResponse.json({ success: true });
126	    } else {
127	      logRouteError(
128	        functionName,
129	        'POST',
130	        '/api/auth/totp/confirm',
131	        'Invalid authenticator code',
132	        user
133	      );
134	      return NextResponse.json(
135	        { error: 'Invalid authenticator code' },
136	        { status: 400 }
137	      );
138	    }
139	  } catch (error: unknown) {
140	    const errorMessage =
141	      error instanceof Error ? error.message : 'Internal server error';
142	    logRouteError(
