1	import {
2	  generateOTPAuthURI,
3	  generateTOTPSecret,
4	} from '@/app/api/lib/helpers/auth/totp';
5	import { connectDB } from '@/app/api/lib/middleware/db';
6	import UserModel from '@/app/api/lib/models/user';
7	import { NextRequest, NextResponse } from 'next/server';
8	import QRCode from 'qrcode';
9	import {
10	  logRouteFetch,
11	  logRouteError,
12	  extractUserFromRequest,
13	} from '@/app/api/lib/utils/routeLogger';
14	
15	/**
16	 * POST /api/auth/totp/recover/verify
17	 *
18	 * Validates a time-limited recovery token that was emailed to the user during the
19	 * VM recovery flow. If valid, generates a new TOTP secret and QR code without
20	 * immediately disabling the old secret, so existing 2FA protection is maintained
21	 * until the new code is confirmed via POST /api/auth/totp/confirm.
22	 *
23	 * Body fields:
24	 * @param {string} token - Required. The recovery token from the emailed link, matched
25	 *                       against `totpRecoveryToken` with expiry enforced via `totpRecoveryExpires`.
26	 */
27	export async function POST(req: NextRequest) {
28	  const startTime = Date.now();
29	  const functionName = 'POST /api/auth/totp/recover/verify';
30	  const user = extractUserFromRequest(req);
31	
32	  try {
33	    const { token } = await req.json();
34	    if (!token) {
35	      logRouteError(
36	        functionName,
37	        'POST',
38	        '/api/auth/totp/recover/verify',
39	        'Token is required',
40	        user
41	      );
42	      return NextResponse.json({ error: 'Token is required' }, { status: 400 });
43	    }
44	
45	    console.log('[TOTP Verify] Checking token:', token);
46	    await connectDB();
47	    const foundUser = await UserModel.findOne({
48	      totpRecoveryToken: token,
49	      totpRecoveryExpires: { $gt: new Date() },
50	    });
51	
52	    if (!foundUser) {
53	      console.log('[TOTP Verify] No user found for token or token expired');
54	      // Let's check if the token exists at all without the expiry filter for debugging
55	      const userWithToken = await UserModel.findOne({
56	        totpRecoveryToken: token,
57	      });
58	      if (userWithToken) {
59	        console.log(
60	          '[TOTP Verify] Found user but token EXPIRED. Expiry:',
61	          userWithToken.totpRecoveryExpires,
62	          'Current:',
63	          new Date()
64	        );
65	      } else {
66	        console.log('[TOTP Verify] Token not found in database at all');
67	      }
68	      logRouteError(
69	        functionName,
70	        'POST',
71	        '/api/auth/totp/recover/verify',
72	        'Invalid or expired recovery token',
73	        user
74	      );
75	      return NextResponse.json(
76	        { error: 'Invalid or expired recovery token' },
77	        { status: 400 }
78	      );
79	    }
80	
81	    console.log('[TOTP Verify] User found:', foundUser.username);
82	
83	    // ============================================================================
84	    // STEP 1: Generate NEW secret
85	    // ============================================================================
86	    const secret = generateTOTPSecret();
87	    const appName = 'Evolution One CMS';
88	    const uri = generateOTPAuthURI(
89	      foundUser.username || foundUser.emailAddress,
90	      appName,
91	      secret
92	    );
93	    const qrCodeUrl = await QRCode.toDataURL(uri);
94	
95	    // ============================================================================
96	    // STEP 2: Update totpTempSecret
97	    // Use totpTempSecret instead of overwriting totpSecret/totpEnabled immediately
98	    // This allows the user to maintain their current 2FA protection until the new one is verified
99	    // ============================================================================
100	    const updateResult = await UserModel.findOneAndUpdate(
101	      { _id: foundUser._id },
102	      {
103	        $set: {
104	          totpTempSecret: secret,
105	          // totpRecoveryToken: null, // Keep the token for the confirm step if needed, or clear it if preferred
106	          // totpRecoveryExpires: null
107	        },
108	      },
109	      { strict: false }
110	    );
111	    if (!updateResult) {
112	      logRouteError(
113	        functionName,
114	        'POST',
115	        '/api/auth/totp/recover/verify',
116	        'Failed to save new TOTP secret',
117	        user
118	      );
119	      return NextResponse.json(
120	        { error: 'Failed to save new TOTP secret' },
121	        { status: 500 }
122	      );
123	    }
124	
125	    console.log(
126	      '[TOTP Verify] Tokens cleared and new secret saved for:',
127	      foundUser.username
128	    );
129	
130	    const duration = Date.now() - startTime;
131	    logRouteFetch(
132	      functionName,
133	      'POST',
134	      '/api/auth/totp/recover/verify',
135	      1,
136	      user,
137	      duration
138	    );
139	
140	    return NextResponse.json({
141	      success: true,
142	      qrCodeUrl,
143	      secret,
144	      username: foundUser.username,
145	    });
146	  } catch (e) {
147	    const errorMessage =
148	      e instanceof Error ? e.message : 'Internal server error';
149	    logRouteError(
150	      functionName,
151	      'POST',
152	      '/api/auth/totp/recover/verify',
153	      errorMessage,
154	      user
155	    );
156	    return NextResponse.json(
157	      { success: false, error: 'Internal server error' },
158	      { status: 500 }
159	    );
160	  }
161	}
