16	 *
17	 * Initiates 2FA recovery for a Vault Manager or higher-privileged user who has
18	 * lost access to their authenticator app. Takes no request body; identity is
19	 * derived from the session cookie. Generates a one-hour recovery token, persists
20	 * it to the user document, and sends a recovery link to the account's email address.
21	 * Restricted to roles: vault-manager, location admin, manager, admin, developer.
22	 */
23	export async function POST() {
24	  const startTime = Date.now();
25	  const functionName = 'POST /api/auth/totp/recover/vm';
26	  const user = extractUserFromRequest(null);
27	
