35	        'Unauthorized',
36	        user
37	      );
38	      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
39	    }
40	
41	    await connectDB();
42	    const foundUser = await UserModel.findOne({ _id: session._id });
43	    if (!foundUser) {
44	      logRouteError(
45	        functionName,
46	        'POST',
47	        '/api/auth/totp/recover/vm',
48	        'User not found',
49	        user
50	      );
51	      return NextResponse.json({ error: 'User not found' }, { status: 404 });
52	    }
53	
54	    // Role check: must be vault-manager or admin/developer
55	    const userRoles = Array.isArray(foundUser.roles) ? foundUser.roles : [];
56	    const isVMOrHigher = userRoles.some((role: string) =>
57	      [
58	        'vault-manager',
59	        'admin',
60	        'developer',
61	        'manager',
62	        'location admin',
63	      ].includes(role.toLowerCase())
64	    );
65	
66	    if (!isVMOrHigher) {
67	      logRouteError(
68	        functionName,
69	        'POST',
70	        '/api/auth/totp/recover/vm',
71	        'Not authorized for email recovery flow',
72	        user
73	      );
74	      return NextResponse.json(
75	        { error: 'Not authorized for email recovery flow' },
76	        { status: 403 }
77	      );
78	    }
79	
80	    if (!foundUser.emailAddress) {
81	      logRouteError(
82	        functionName,
83	        'POST',
84	        '/api/auth/totp/recover/vm',
