16	/**
17	 * POST /api/auth/totp/setup
18	 *
19	 * Generates a TOTP secret and QR code for the authenticated user to scan with
20	 * their authenticator app. Takes no request body; identity is derived from the
21	 * session cookie. The secret is persisted as `totpSecret` but `totpEnabled`
22	 * remains false until the code is confirmed via POST /api/auth/totp/confirm.
23	 */
24	export async function POST() {
25	  const startTime = Date.now();
26	  const functionName = 'POST /api/auth/totp/setup';
27	  const user = extractUserFromRequest(null);
28	
29	  try {
30	    const session = await getUserFromServer();
31	    if (!session || !session._id) {
32	      logRouteError(
33	        functionName,
34	        'POST',
35	        '/api/auth/totp/setup',
36	        'Unauthorized',
37	        user
38	      );
39	      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
40	    }
41	
42	    await connectDB();
43	    const foundUser = await UserModel.findOne({ _id: session._id });
44	    if (!foundUser) {
45	      logRouteError(
46	        functionName,
47	        'POST',
48	        '/api/auth/totp/setup',
49	        'User not found',
50	        user
51	      );
52	      return NextResponse.json({ error: 'User not found' }, { status: 404 });
53	    }
54	
55	    // ============================================================================
56	    // STEP 1: Generate secret if not exists
57	    // ============================================================================
58	    let secret = foundUser.totpSecret;
59	    if (!secret) {
60	      secret = generateTOTPSecret();
61	      foundUser.totpSecret = secret;
62	      foundUser.totpEnabled = false; // Reset just in case
63	      await foundUser.save();
64	    }
65	
66	    const appName = 'Evolution One CMS';
67	    const uri = generateOTPAuthURI(
68	      foundUser.username || foundUser.emailAddress,
69	      appName,
70	      secret
71	    );
72	    const qrCodeUrl = await QRCode.toDataURL(uri);
73	
74	    const duration = Date.now() - startTime;
75	    logRouteFetch(
76	      functionName,
77	      'POST',
78	      '/api/auth/totp/setup',
79	      1,
80	      user,
81	      duration
82	    );
83	
84	    return NextResponse.json({
85	      success: true,
86	      qrCodeUrl,
87	      secret, // Also provide the text secret for manual entry
88	    });
89	  } catch (e) {
90	    const errorMessage =
91	      e instanceof Error ? e.message : 'Internal server error';
92	    logRouteError(
93	      functionName,
94	      'POST',
95	      '/api/auth/totp/setup',
96	      errorMessage,
97	      user
98	    );
99	    return NextResponse.json(
100	      { success: false, error: 'Internal server error' },
101	      { status: 500 }
102	    );
103	  }
104	}
