136	        isPaid: true,
137	        licenceKey: 'LIC-MM2F4V11-6Y189A',
138	        status: 'active',
139	        deletedAt: null,
140	        createdAt: currentDateTime,
141	        updatedAt: null,
142	      },
143	      {
144	        _id: 'c03b094083226f216b3fc39c',
145	        name: 'Cabana',
