1	/**
2	 * PUT /api/profile
3	 *
4	 * Updates the authenticated user's profile. Called from the profile settings
5	 * page when the user saves personal information or changes their password.
6	 * Admin and developer roles may also update their own licencee and location
7	 * assignments via this endpoint. Any change to password, licencees, or
8	 * locations increments sessionVersion to force re-authentication on other
9	 * sessions. Duplicate username/email checks are enforced across all users.
10	 * Cashiers using a temporary password may skip providing currentPassword on
11	 * their first password change.
12	 *
13	 * Body fields:
14	 * @param username      {string}   Required. New or unchanged username.
15	 * @param firstName     {string}   Required. First name; letters and spaces only.
16	 * @param lastName      {string}   Required. Last name; letters and spaces only.
17	 * @param emailAddress  {string}   Required. Email address.
18	 * @param phone         {string}   Required. Phone number (digits, spaces, hyphens, parens, leading +).
19	 * @param otherName     {string}   Optional. Middle or other name.
20	 * @param gender        {string}   Optional. Gender value; validated when explicitly sent.
21	 * @param dateOfBirth   {string}   Optional. ISO date string (YYYY-MM-DD); must not be in the future.
22	 * @param currentPassword {string} Conditional. Current password; required for non-cashier password
23	 *   changes. Cashiers on a temporary password may omit this field.
24	 * @param newPassword   {string}   Conditional. Required when changing password; must meet strength
25	 *   requirements and must not match the current or last 2 passwords.
26	 * @param confirmPassword {string} Conditional. Must match newPassword exactly.
27	 * @param licenceeIds   {string[]} Optional. Admin/developer only — replace assigned licencees.
28	 * @param locationIds   {string[]} Optional. Admin/developer only — replace assigned locations.
29	 *
30	 * @module app/api/profile/route
31	 */
32	
33	import { getUserIdFromServer } from '@/app/api/lib/helpers/users/users';
34	import { connectDB } from '@/app/api/lib/middleware/db';
35	import UserModel from '@/app/api/lib/models/user';
36	import { hashPassword } from '@/app/api/lib/utils/validation';
37	import { logActivity } from '@/app/api/lib/helpers/activityLogger';
38	import { NextRequest, NextResponse } from 'next/server';
39	import type { ProfileUpdatePayload } from '@/shared/types/users';
40	import {
41	  logRouteUpdate,
42	  logRouteError,
43	  extractUserFromRequest,
44	} from '@/app/api/lib/utils/routeLogger';
45	import { getInvalidProfileFields, hasInvalidProfileFields } from '@/app/api/lib/helpers/profileValidation';
46	import {
47	  normalizeProfileFields,
48	  validateProfileFields,
49	  validateNonAdminAssignments,
50	  checkDuplicateUsernameEmail,
51	  verifyCurrentPassword,
52	  checkPasswordAgainstHistory,
53	  normalizeIdArray,
54	  canManageAssignments,
55	  getExistingAssignments,
56	  buildUpdateOperation,
57	} from '@/app/api/lib/helpers/profileOperations';
58	
59	export async function PUT(request: NextRequest) {
60	  const startTime = Date.now();
61	  const functionName = 'PUT /api/profile';
62	  const logUser = extractUserFromRequest(request);
63	
64	  try {
65	    // ============================================================================
66	    // STEP 1: Connect to database
67	    // ============================================================================
68	    await connectDB();
69	
70	    // ============================================================================
71	    // STEP 2: Authenticate user and get user ID
72	    // ============================================================================
73	    const userId = await getUserIdFromServer();
74	    if (!userId) {
75	      logRouteError(functionName, 'PUT', '/api/profile', 'Unauthorized', logUser);
76	      return NextResponse.json(
77	        { success: false, message: 'Unauthorized - Invalid or missing session' },
78	        { status: 401 }
79	      );
80	    }
81	
82	    // ============================================================================
83	    // STEP 3: Parse and validate request body
84	    // ============================================================================
85	    const body = (await request.json()) as ProfileUpdatePayload;
86	    const fields = normalizeProfileFields(body);
87	
88	    // ============================================================================
89	    // STEP 4: Fetch user for validation and security checks
90	    // ============================================================================
91	    const user = await UserModel.findOne({ _id: userId }).select('+password');
92	    if (!user) {
93	      return NextResponse.json(
94	        { success: false, message: 'User not found' },
95	        { status: 404 }
96	      );
97	    }
98	
99	    const isTemporaryPassword = user.tempPasswordChanged === false;
100	
101	    // ============================================================================
102	    // STEP 5: Validate all profile fields
103	    // ============================================================================
104	    const { isValid, errors, passwordChangeRequested } = validateProfileFields(
105	      fields,
106	      body.gender,
107	      isTemporaryPassword
108	    );
109	
110	    if (!isValid) {
111	      return NextResponse.json(
112	        { success: false, message: 'Validation failed', errors },
113	        { status: 400 }
114	      );
115	    }
116	
117	    // ============================================================================
118	    // STEP 6: Check non-admin assignment restrictions
119	    // ============================================================================
120	    const userRoles = (user.roles as string[] | undefined)?.map(role =>
121	      String(role).toLowerCase()
122	    ) || [];
123	    const hasAssignmentPermission = canManageAssignments(userRoles);
124	
125	    const requestedLicenceeIds = normalizeIdArray(body.licenceeIds);
126	    const requestedLocationIds = normalizeIdArray(body.locationIds);
127	
128	    if (!hasAssignmentPermission) {
129	      const assignmentErrors = validateNonAdminAssignments(
130	        requestedLicenceeIds,
131	        requestedLocationIds
132	      );
133	      if (Object.keys(assignmentErrors).length > 0) {
134	        return NextResponse.json(
135	          { success: false, message: 'Validation failed', errors: assignmentErrors },
136	          { status: 400 }
137	        );
138	      }
139	    }
140	
141	    // ============================================================================
142	    // STEP 7: Check for duplicate username/email
143	    // ============================================================================
144	    const duplicateResult = await checkDuplicateUsernameEmail(
145	      userId,
146	      fields.username,
147	      fields.emailAddress,
148	      user.username || '',
149	      user.emailAddress || ''
150	    );
151	
152	    if (duplicateResult?.isDuplicate) {
153	      return NextResponse.json(
154	        {
155	          success: false,
156	          message: duplicateResult.message,
157	          errors: { [duplicateResult.field as string]: duplicateResult.message },
158	        },
159	        { status: 409 }
160	      );
161	    }
162	
163	    // ============================================================================
164	    // STEP 8: Verify current password if changing password
165	    // ============================================================================
166	    const passwordVerifyResult = await verifyCurrentPassword(
167	      passwordChangeRequested,
168	      fields.currentPassword,
169	      user.password || '',
170	      isTemporaryPassword
171	    );
172	
173	    if (!passwordVerifyResult.ok) {
174	      return NextResponse.json(
175	        {
176	          success: false,
177	          message: passwordVerifyResult.errorMessage,
178	          errors: passwordVerifyResult.fieldErrors,
179	        },
180	        { status: 400 }
181	      );
182	    }
183	
184	    // ============================================================================
185	    // STEP 9: Check password against history
186	    // ============================================================================
187	    if (passwordChangeRequested && fields.newPassword) {
188	      const historyResult = await checkPasswordAgainstHistory(
189	        fields.newPassword,
190	        user.password || '',
191	        (user.previousPasswords as string[]) || []
192	      );
193	
194	      if (!historyResult.ok) {
195	        return NextResponse.json(
196	          {
197	            success: false,
198	            message: historyResult.errorMessage,
199	            errors: historyResult.fieldErrors,
200	          },
201	          { status: 400 }
202	        );
203	      }
204	    } else if (!user.passwordUpdatedAt && !isTemporaryPassword) {
205	      return NextResponse.json(
206	        {
207	          success: false,
208	          message: 'You must set a new password to continue.',
209	          errors: { newPassword: 'You must set a new password to continue.' },
210	        },
211	        { status: 400 }
212	      );
213	    }
214	
215	    // ============================================================================
216	    // STEP 10: Build update operation
217	    // ============================================================================
218	    const { existingLicencees, existingLocations } = getExistingAssignments(
219	      user as { assignedLicencees?: string[]; assignedLocations?: string[] }
220	    );
221	
222	    const newPasswordHash = passwordChangeRequested && fields.newPassword
223	      ? await hashPassword(fields.newPassword)
224	      : undefined;
225	    const oldPasswordHash = user.password;
226	
227	    const { updateSet, unsetMap, incrementSession } = buildUpdateOperation({
228	      fields,
229	      existingLicencees,
230	      existingLocations,
231	      hasAssignmentPermission,
232	      passwordChangeRequested,
233	      isTemporaryPassword,
234	      newPasswordHash,
235	      oldPasswordHash,
236	      requestedLicenceeIds,
237	      requestedLocationIds,
238	    });
239	
240	    const updateOperation: Record<string, unknown> = {
241	      $set: updateSet,
242	      $unset: unsetMap,
243	    };
244	
245	    if (incrementSession) {
246	      updateOperation.$inc = { sessionVersion: 1 };
247	    }
248	
249	    // ============================================================================
250	    // STEP 11: Update user in database
251	    // ============================================================================
252	    const updatedUser = await UserModel.findOneAndUpdate(
253	      { _id: userId },
254	      updateOperation,
255	      { new: true }
256	    );
257	
258	    if (!updatedUser) {
259	      return NextResponse.json(
260	        { success: false, message: 'Failed to update profile' },
261	        { status: 500 }
262	      );
263	    }
264	
265	    // ============================================================================
266	    // STEP 12: Return updated user with validation status
267	    // ============================================================================
268	    const { invalidFields, reasons } = getInvalidProfileFields(updatedUser, {
269	      rawPassword: fields.newPassword || undefined,
270	    });
271	    const requiresProfileUpdate = hasInvalidProfileFields(invalidFields);
272	
273	    const updatedObject = updatedUser.toObject();
274	    delete updatedObject.password;
275	
276	    const duration = Date.now() - startTime;
277	    logRouteUpdate(functionName, 'PUT', '/api/profile', 1, logUser, duration);
278	
279	    logActivity({
280	      action: 'update',
281	      details: passwordChangeRequested
282	        ? `User ${user.username} changed their password and updated profile`
283	        : `User ${user.username} updated their profile`,
284	      userId: String(userId),
285	      username: user.username || user.emailAddress || String(userId),
286	      metadata: {
287	        resource: 'profile',
288	        resourceId: String(userId),
289	        resourceName: user.username || String(userId),
290	        changes: [
291	          user.username !== fields.username
292	            ? { field: 'username', oldValue: user.username, newValue: fields.username }
293	            : null,
294	          user.emailAddress !== fields.emailAddress
295	            ? { field: 'emailAddress', oldValue: user.emailAddress, newValue: fields.emailAddress }
296	            : null,
297	          passwordChangeRequested
298	            ? { field: 'password', oldValue: '[redacted]', newValue: '[redacted]' }
299	            : null,
300	          incrementSession
301	            ? { field: 'sessionVersion', oldValue: 'previous', newValue: 'incremented' }
302	            : null,
303	        ].filter(Boolean),
304	      },
305	    }).catch(err =>
306	      logRouteError(functionName, 'PUT', '/api/profile', err instanceof Error ? err : String(err), logUser)
307	    );
308	
309	    return NextResponse.json({
310	      success: true,
311	      user: {
312	        _id: updatedObject._id,
313	        username: updatedObject.username,
314	        emailAddress: updatedObject.emailAddress,
315	        profile: updatedObject.profile,
316	        roles: updatedObject.roles,
317	        rel: updatedObject.rel,
318	        isEnabled: updatedObject.isEnabled,
319	        assignedLocations: updatedObject.assignedLocations || undefined,
320	        assignedLicencees: updatedObject.assignedLicencees || undefined,
321	        tempPasswordChanged: updatedObject.tempPasswordChanged,
322	        requiresProfileUpdate,
323	        requiresPasswordUpdate: !!invalidFields.password,
324	        invalidProfileFields: invalidFields,
325	        invalidProfileReasons: reasons,
326	      },
327	      requiresProfileUpdate,
328	      requiresPasswordUpdate: !!invalidFields.password,
329	      invalidProfileFields: invalidFields,
330	      invalidProfileReasons: reasons,
331	      sessionVersionIncremented: incrementSession,
332	    });
333	  } catch (error) {
334	    const errorMessage = error instanceof Error ? error.message : 'Failed to update profile';
335	    logRouteError(functionName, 'PUT', '/api/profile', errorMessage, logUser);
336	    return NextResponse.json(
337	      { success: false, message: errorMessage },
338	      { status: 500 }
339	    );
340	  }
341	}
