1	/**
2	 * Rename Licencee Migration API Route
3	 *
4	 * One-off data migration that renames legacy licencee field variants across all
5	 * MongoDB collections using $rename. Safe to re-run — documents that already use
6	 * the target field name are not modified.
7	 *
8	 * @module app/api/admin/migrations/rename-licencee/route
9	 */
10	
11	import { connectDB } from '@/app/api/lib/middleware/db';
12	import mongoose from 'mongoose';
13	import { NextResponse } from 'next/server';
14	import { logRouteFetch, logRouteError } from '@/app/api/lib/utils/routeLogger';
15	
16	/**
17	 * GET /api/admin/migrations/rename-licencee
18	 *
19	 * Iterates every collection in the connected database and applies $rename
20	 * operations to normalise licencee field names (e.g. `licencee`,
21	 * `rel.licencee`, `assignedLicencees`, `licenceeId`, `rel.licenceeId`).
22	 * Returns a list of collections and field renames where at least one document
23	 * was modified. No request body or query parameters are required.
24	 */
25	export async function GET() {
26	  const startTime = Date.now();
27	  const functionName = 'GET /api/admin/migrations/rename-licencee';
28	
29	  try {
30	    await connectDB();
31	
32	    // To avoid dynamic imports matching everything that might fail in Webpack,
33	    // we just use the native mongoose connection to get all collections and update them
34	    const db = mongoose.connection.db;
35	    if (!db) {
36	      logRouteError(
37	        functionName,
38	        'GET',
39	        '/api/admin/migrations/rename-licencee',
40	        'DB connection not ready',
41	        null
42	      );
43	      return NextResponse.json(
44	        { error: 'DB connection not ready' },
45	        { status: 500 }
46	      );
47	    }
48	
49	    const collections = await db.collections();
50	    const results: Array<{
51	      collection: string;
52	      desc: string;
53	      modifiedCount: number;
54	    }> = [];
55	
56	    for (const collection of collections) {
57	      const collectionName = collection.collectionName;
58	
59	      const renames: Array<{
60	        filter: Record<string, unknown>;
61	        rename: Record<string, string>;
62	        desc: string;
63	      }> = [
64	        {
65	          filter: { licencee: { $exists: true } },
66	          rename: { licencee: 'licencee' },
67	          desc: 'licencee -> licencee',
68	        },
69	        {
70	          filter: { 'rel.licencee': { $exists: true } },
71	          rename: { 'rel.licencee': 'rel.licencee' },
72	          desc: 'rel.licencee -> rel.licencee',
73	        },
74	        {
75	          filter: { assignedLicencees: { $exists: true } },
76	          rename: { assignedLicencees: 'assignedLicencees' },
77	          desc: 'assignedLicencees -> assignedLicencees',
78	        },
79	        {
80	          filter: { licenceeId: { $exists: true } },
81	          rename: { licenceeId: 'licenceeId' },
82	          desc: 'licenceeId -> licenceeId',
83	        },
84	        {
85	          filter: { 'rel.licenceeId': { $exists: true } },
86	          rename: { 'rel.licenceeId': 'rel.licenceeId' },
87	          desc: 'rel.licenceeId -> rel.licenceeId',
88	        },
89	      ];
90	
91	      for (const { filter, rename, desc } of renames) {
92	        const result = await collection.updateMany(filter, { $rename: rename });
93	        if (result && result.modifiedCount > 0) {
94	          results.push({
95	            collection: collectionName,
96	            desc,
97	            modifiedCount: result.modifiedCount,
98	          });
99	        }
100	      }
101	    }
102	
103	    const duration = Date.now() - startTime;
104	    logRouteFetch(
105	      functionName,
106	      'GET',
107	      '/api/admin/migrations/rename-licencee',
108	      results.length,
109	      null,
110	      duration
111	    );
112	    return NextResponse.json({ success: true, results });
113	  } catch (e) {
114	    const errorMessage = e instanceof Error ? e.message : 'Unknown error';
115	    logRouteError(
116	      functionName,
117	      'GET',
118	      '/api/admin/migrations/rename-licencee',
119	      errorMessage,
120	      null
121	    );
122	    return NextResponse.json(
123	      { success: false, error: 'Internal server error' },
124	      { status: 500 }
125	    );
126	  }
127	}
