1	/**
2	 * Repair SAS Times Admin API Route
3	 *
4	 * This route handles repairing SAS times in collections by:
5	 * - Normalizing timestamps to 8AM Trinidad time (12:00 UTC)
6	 * - Finding previous collections for correct SAS time windows
7	 * - Calculating corrected SAS metrics
8	 * - Updating collections and machine timestamps (in commit mode)
9	 *
10	 * Supports:
11	 * - Dry-run mode (preview changes) and commit mode (apply changes)
12	 * - Filtering by locationReportId, machineId, or date range
13	 *
14	 * @module app/api/admin/repair-sas-times/route
15	 */
16	
17	import { connectDB } from '@/app/api/lib/middleware/db';
18	import { repairSasTimesForCollections } from '@/app/api/lib/helpers/collectionReport/fixes/adminRepair';
19	import { NextRequest, NextResponse } from 'next/server';
20	import {
21	  logRouteCreate,
22	  logRouteError,
23	  extractUserFromRequest,
24	} from '@/app/api/lib/utils/routeLogger';
25	
26	export const dynamic = 'force-dynamic';
27	export const revalidate = 0;
28	export const runtime = 'nodejs';
29	
30	type RepairMode = 'dry-run' | 'commit';
31	
32	/**
33	 * POST /api/admin/repair-sas-times
34	 *
35	 * Repairs incorrect SAS timestamps in collection records by normalising them to
36	 * the 8 AM Trinidad-time gaming-day boundary and recalculating SAS metrics.
37	 * Run in 'dry-run' mode first to preview changes, then 'commit' to apply them.
38	 * No authentication guard in the handler — restrict at infrastructure level.
39	 *
40	 * Query params:
41	 * @param mode             {string}  Optional. 'dry-run' (default) previews changes; 'commit' applies them.
42	 * @param locationReportId {string}  Optional. Limit repair to collections belonging to this report ID.
43	 * @param machineId        {string}  Optional. Limit repair to collections for this machine ID.
44	 * @param startDate        {string}  Optional. ISO date string; only include collections at or after this timestamp.
45	 * @param endDate          {string}  Optional. ISO date string; only include collections at or before this timestamp.
46	 */
47	export async function POST(req: NextRequest) {
48	  const startTime = Date.now();
49	  const functionName = 'POST /api/admin/repair-sas-times';
50	  const user = extractUserFromRequest(req);
51	
52	  try {
53	    // ============================================================================
54	    // STEP 1: Connect to database
55	    // ============================================================================
56	    await connectDB();
57	
58	    // ============================================================================
59	    // STEP 2: Parse query parameters
60	    // ============================================================================
61	    const { searchParams } = new URL(req.url);
62	    const mode = (searchParams.get('mode') as RepairMode) || 'dry-run';
63	    const locationReportId = searchParams.get('locationReportId') || undefined;
64	    const machineId = searchParams.get('machineId') || undefined;
65	    const startDateParam = searchParams.get('startDate');
66	    const endDateParam = searchParams.get('endDate');
67	
68	    // ============================================================================
69	    // STEP 3: Build filter from parameters
70	    // ============================================================================
71	    const filter: Record<string, unknown> = {};
72	    if (locationReportId) filter.locationReportId = locationReportId;
73	    if (machineId) filter.machineId = machineId;
74	
75	    if (startDateParam || endDateParam) {
76	      const ts: Record<string, Date> = {};
77	      if (startDateParam) ts.$gte = new Date(startDateParam);
78	      if (endDateParam) ts.$lte = new Date(endDateParam);
79	      filter.timestamp = ts;
80	    }
81	
82	    // ============================================================================
83	    // STEP 4: Execute repair operation
84	    // ============================================================================
85	    const results = await repairSasTimesForCollections(filter, mode);
86	
87	    // ============================================================================
88	    // STEP 5: Return repair results
89	    // ============================================================================
90	    const duration = Date.now() - startTime;
91	    logRouteCreate(
92	      functionName,
93	      'POST',
94	      '/api/admin/repair-sas-times',
95	      results.count ?? 0,
96	      user,
97	      duration
98	    );
99	
100	    return NextResponse.json(results);
101	  } catch (error: unknown) {
102	    const errorMessage =
103	      error instanceof Error ? error.message : 'Unknown error';
104	    logRouteError(
105	      functionName,
106	      'POST',
107	      '/api/admin/repair-sas-times',
108	      errorMessage,
109	      user
110	    );
111	    console.error('[Admin Repair SAS Times] Error:', errorMessage);
112	
113	    return NextResponse.json(
114	      { success: false, error: errorMessage },
115	      { status: 500 }
116	    );
117	  }
118	}
