1	/**
2	 * Resolve Machine Names in Activity Logs
3	 *
4	 * Scans activity logs where resourceName is a raw ObjectID string (24-char hex),
5	 * queries the Machine model to resolve the human-readable name (serialNumber / custom.name),
6	 * and updates the log in place.
7	 *
8	 * GET ?limit=100  — process up to `limit` logs per call, returns progress counts.
9	 */
10	
11	import { connectDB } from '@/app/api/lib/middleware/db';
12	import { ActivityLog } from '@/app/api/lib/models/activityLog';
13	import { Machine } from '@/app/api/lib/models/machines';
14	import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
15	import type { ActivityLogDocument, GamingMachine } from '@/shared/types';
16	import { NextRequest, NextResponse } from 'next/server';
17	import {
18	  logRouteFetch,
19	  logRouteError,
20	  extractUserFromRequest,
21	} from '@/app/api/lib/utils/routeLogger';
22	
23	export const dynamic = 'force-dynamic';
24	export const revalidate = 0;
25	export const runtime = 'nodejs';
26	
27	const OBJECT_ID_REGEX = /^[a-fA-F0-9]{24}$/;
28	
29	/**
30	 * GET /api/admin/resolve-machine-names
31	 *
32	 * Back-fill maintenance operation that finds activity log entries whose
33	 * `resourceName` is a raw 24-character ObjectID hex string, resolves each ID to
34	 * the machine's human-readable name (serialNumber or custom.name), and updates
35	 * the log documents in place. Call repeatedly until `remaining` reaches zero.
36	 * Restricted to developer role.
37	 *
38	 * Query params:
39	 * @param {number} [limit] - Optional. Maximum logs to process per call (default 100, max 500).
40	 */
41	export async function GET(request: NextRequest) {
42	  return withApiAuth(request, async ({ userRoles }) => {
43	    const startTime = Date.now();
44	    const functionName = 'GET /api/admin/resolve-machine-names';
45	    const user = extractUserFromRequest(request);
46	
47	    const normalizedRoles = userRoles.map(r => String(r).toLowerCase());
48	    if (!normalizedRoles.includes('developer')) {
49	      logRouteError(
50	        functionName,
51	        'GET',
52	        '/api/admin/resolve-machine-names',
53	        'Developer access required',
54	        user
55	      );
56	      return NextResponse.json(
57	        { success: false, message: 'Developer access required' },
58	        { status: 403 }
59	      );
60	    }
61	
62	    await connectDB();
63	
64	    const { searchParams } = new URL(request.url);
65	    const limit = Math.min(parseInt(searchParams.get('limit') || '100'), 500);
66	
67	    const total = await ActivityLog.countDocuments({
68	      resourceName: { $regex: /^[a-fA-F0-9]{24}$/ },
69	      deletedAt: null,
70	    });
71	
72	    if (total === 0) {
73	      const duration = Date.now() - startTime;
74	      logRouteFetch(
75	        functionName,
76	        'GET',
77	        '/api/admin/resolve-machine-names',
78	        0,
79	        user,
80	        duration
81	      );
82	      return NextResponse.json({
83	        success: true,
84	        updated: 0,
85	        total: 0,
86	        remaining: 0,
87	      });
88	    }
89	
90	    const logsToResolve = await ActivityLog.find(
91	      { resourceName: { $regex: /^[a-fA-F0-9]{24}$/ }, deletedAt: null },
92	      { _id: 1, resourceName: 1 }
93	    )
94	      .limit(limit)
95	      .lean<ActivityLogDocument[]>();
96	
97	    const objectIds = [
98	      ...new Set(
99	        logsToResolve
100	          .map(l => String(l.resourceName))
101	          .filter(n => OBJECT_ID_REGEX.test(n))
102	      ),
103	    ];
104	
105	    const machines = await Machine.find(
106	      { _id: { $in: objectIds } },
107	      { _id: 1, serialNumber: 1, 'custom.name': 1 }
108	    ).lean<GamingMachine[]>();
109	
110	    const machineNameMap = new Map<string, string>();
111	    for (const machine of machines) {
112	      const id = String(machine._id);
113	      const serial = machine.serialNumber?.trim() || '';
114	      const customName = (machine.custom?.name || '').trim();
115	      const displayName = serial || customName || id;
116	      machineNameMap.set(id, displayName);
117	    }
118	
119	    let updated = 0;
120	    const bulkOps: Array<{
121	      updateOne: {
122	        filter: { _id: string };
123	        update: { $set: { resourceName: string } };
124	      };
125	    }> = [];
126	
127	    for (const log of logsToResolve) {
128	      const rawName = String(log.resourceName);
129	      if (!OBJECT_ID_REGEX.test(rawName)) continue;
130	      const resolved = machineNameMap.get(rawName);
131	      if (resolved && resolved !== rawName) {
132	        bulkOps.push({
133	          updateOne: {
134	            filter: { _id: String(log._id) },
135	            update: { $set: { resourceName: resolved } },
136	          },
137	        });
138	        updated++;
139	      }
140	    }
141	
142	    if (bulkOps.length > 0) {
143	      await ActivityLog.bulkWrite(
144	        bulkOps as Parameters<typeof ActivityLog.bulkWrite>[0]
145	      );
146	    }
147	
148	    const remaining = await ActivityLog.countDocuments({
149	      resourceName: { $regex: /^[a-fA-F0-9]{24}$/ },
150	      deletedAt: null,
151	    });
152	
153	    const duration = Date.now() - startTime;
154	    logRouteFetch(
155	      functionName,
156	      'GET',
157	      '/api/admin/resolve-machine-names',
158	      updated,
159	      user,
160	      duration
161	    );
162	    return NextResponse.json({ success: true, updated, total, remaining });
163	  });
164	}
