1	/**
2	 * Reset Cashier Password API
3	 *
4	 * POST /api/admin/cashiers/reset
5	 *
6	 * Forces a password reset for a cashier account.
7	 *
8	 * @module app/api/admin/cashiers/reset/route
9	 */
10	
11	import { getUserFromServer } from '@/app/api/lib/helpers/users/users';
12	import { connectDB } from '@/app/api/lib/middleware/db';
13	import UserModel from '@/app/api/lib/models/user';
14	import { nanoid } from 'nanoid';
15	import { NextRequest, NextResponse } from 'next/server';
16	import {
17	  logRouteCreate,
18	  logRouteError,
19	  extractUserFromRequest,
20	} from '@/app/api/lib/utils/routeLogger';
21	
22	type ResetPasswordRequest = {
23	  cashierId: string;
24	};
25	
26	/**
27	 * POST /api/admin/cashiers/reset
28	 *
29	 * Generates a new temporary password for an existing cashier account and forces
30	 * a password change on next login. The plaintext temporary password is returned
31	 * in the response for the vault manager to relay. Accessible to developer, admin,
32	 * owner, manager, vault-manager, and location admin roles; non-admin callers are
33	 * further restricted to cashiers within their shared licencees.
34	 *
35	 * Body fields:
36	 * @param {string} cashierId - Required. The ID of the cashier user whose password will be reset.
37	 */
38	export async function POST(request: NextRequest) {
39	  const startTime = Date.now();
40	  const functionName = 'POST /api/admin/cashiers/reset';
41	  const user = extractUserFromRequest(request);
42	
43	  try {
44	    // ============================================================================
45	    // STEP 1: Authentication & Authorization
46	    // ============================================================================
47	    const userPayload = await getUserFromServer();
48	    if (!userPayload) {
49	      logRouteError(
50	        functionName,
51	        'POST',
52	        '/api/admin/cashiers/reset',
53	        'Unauthorized',
54	        user
55	      );
56	      return NextResponse.json(
57	        { success: false, error: 'Unauthorized' },
58	        { status: 401 }
59	      );
60	    }
61	    const userRoles = (userPayload?.roles as string[]) || [];
62	
63	    const hasAdminAccess = userRoles.some(role =>
64	      [
65	        'developer',
66	        'admin',
67	        'owner',
68	        'manager',
69	        'vault-manager',
70	        'vault manager',
71	        'location admin',
72	      ].includes(role)
73	    );
74	
75	    if (!hasAdminAccess) {
76	      logRouteError(
77	        functionName,
78	        'POST',
79	        '/api/admin/cashiers/reset',
80	        'Insufficient permissions',
81	        user
82	      );
83	      return NextResponse.json(
84	        { success: false, error: 'Insufficient permissions' },
85	        { status: 403 }
86	      );
87	    }
88	
89	    // ============================================================================
90	    // STEP 2: Parse and validate request body
91	    // ============================================================================
92	    const body: ResetPasswordRequest = await request.json();
93	    const { cashierId } = body;
94	
95	    if (!cashierId) {
96	      logRouteError(
97	        functionName,
98	        'POST',
99	        '/api/admin/cashiers/reset',
100	        'Cashier ID is required',
101	        user
102	      );
103	      return NextResponse.json(
104	        { success: false, error: 'Cashier ID is required' },
105	        { status: 400 }
106	      );
107	    }
108	
109	    // ============================================================================
110	    // STEP 3: Database connection
111	    // ============================================================================
112	    await connectDB();
113	
114	    // ============================================================================
115	    // STEP 4: Find and validate cashier
116	    // ============================================================================
117	    const cashier = await UserModel.findOne({ _id: cashierId });
118	    if (!cashier) {
119	      logRouteError(
120	        functionName,
121	        'POST',
122	        '/api/admin/cashiers/reset',
123	        `Cashier not found: ${cashierId}`,
124	        user
125	      );
126	      return NextResponse.json(
127	        { success: false, error: 'Cashier not found' },
128	        { status: 404 }
129	      );
130	    }
131	
132	    // Check if user has cashier role
133	    if (!cashier.roles?.includes('cashier')) {
134	      logRouteError(
135	        functionName,
136	        'POST',
137	        '/api/admin/cashiers/reset',
138	        'User is not a cashier',
139	        user
140	      );
141	      return NextResponse.json(
142	        { success: false, error: 'User is not a cashier' },
143	        { status: 400 }
144	      );
145	    }
146	
147	    // ============================================================================
148	    // STEP 4.5: Licencee Validation (Rule 9)
149	    // ============================================================================
150	    const isAdmin =
151	      userRoles.includes('admin') ||
152	      userRoles.includes('developer') ||
153	      userRoles.includes('owner');
154	    if (!isAdmin) {
155	      const { getUserAccessibleLicenceesFromToken } =
156	        await import('../../../lib/helpers/licenceeFilter');
157	      const accessibleLicencees = await getUserAccessibleLicenceesFromToken(
158	        userPayload as Parameters<typeof getUserAccessibleLicenceesFromToken>[0]
159	      );
160	
161	      if (accessibleLicencees !== 'all') {
162	        const cashierLicencees = (cashier.assignedLicencees as string[]) || [];
163	        const hasOverlap = cashierLicencees.some(id =>
164	          accessibleLicencees.includes(String(id))
165	        );
166	
167	        if (!hasOverlap) {
168	          logRouteError(
169	            functionName,
170	            'POST',
171	            '/api/admin/cashiers/reset',
172	            `Insufficient permissions - no shared licencees for cashier: ${cashierId}`,
173	            user
174	          );
175	          return NextResponse.json(
176	            {
177	              success: false,
178	              error:
179	                "Insufficient permissions - You do not have access to this cashier's licencee",
180	            },
181	            { status: 403 }
182	          );
183	        }
184	      }
185	    }
186	
187	    // ============================================================================
188	    // STEP 5: Reset password and force change
189	    // ============================================================================
190	    // Standardize temporary password generation (using nanoid like handleResetCashierPassword expects)
191	    const tempPassword = nanoid(12);
192	
193	    // Hash the password for the database
194	    const { hashPassword } = await import('../../../lib/utils/validation');
195	    cashier.password = await hashPassword(tempPassword);
196	
197	    // Update temp password fields for the new "View Password" system
198	    cashier.tempPassword = tempPassword;
199	    cashier.tempPasswordChanged = false;
200	
201	    // Legacy fields if still used
202	    if ('requiresPasswordChange' in cashier) {
203	      (cashier as unknown as Record<string, unknown>).requiresPasswordChange =
204	        true;
205	    }
206	
207	    cashier.updatedAt = new Date();
208	
209	    await cashier.save();
210	
211	    // ============================================================================
212	    // STEP 6: Return success response
213	    // ============================================================================
214	    const cashierData = cashier.toObject();
215	    const displayName = cashierData.profile
216	      ? `${cashierData.profile.firstName} ${cashierData.profile.lastName}`.trim()
217	      : cashierData.username;
218	
219	    const duration = Date.now() - startTime;
220	    logRouteCreate(
221	      functionName,
222	      'POST',
223	      '/api/admin/cashiers/reset',
224	      1,
225	      user,
226	      duration
227	    );
228	    return NextResponse.json({
229	      success: true,
230	      message: `Password reset for ${displayName}. New temporary password has been set.`,
231	      tempPassword, // Return temporary password for VM to share with cashier
232	      cashier: {
233	        id: cashierData._id,
234	        name: displayName,
235	        email: cashierData.emailAddress,
236	      },
237	    });
238	  } catch (e) {
239	    const errorMessage = e instanceof Error ? e.message : 'Unknown error';
240	    logRouteError(
241	      functionName,
242	      'POST',
243	      '/api/admin/cashiers/reset',
244	      errorMessage,
245	      user
246	    );
247	    return NextResponse.json(
248	      { success: false, error: 'Internal server error' },
249	      { status: 500 }
250	    );
251	  }
252	}
